from math import gcd
import itertools
class Solution:
    def minStable(self, nums, maxC):
        def longest_stable(arr):
            n = len(arr)
            best = 0
            for i in range(n):
                g = 0
                for j in range(i, n):
                    g = gcd(g, arr[j])
                    if g >= 2:
                        if j - i + 1 > best:
                            best = j - i + 1
                    else:
                        break
            return best
        n = len(nums)
        best = longest_stable(nums)
        for r in range(1, maxC + 1):
            for combo in itertools.combinations(range(n), r):
                arr = list(nums)
                for c in combo:
                    arr[c] = 1
                v = longest_stable(arr)
                if v < best:
                    best = v
        return best

