from math import gcd
class Solution:
    def minStable(self, nums, maxC):
        n = len(nums)
        def breakers_needed(L):
            if L >= n:
                return 0
            cnt = 0
            runs = []
            for x in nums:
                tmp = [(x, 1)]
                for pg, pl in runs:
                    tmp.append((gcd(pg, x), pl + 1))
                m = {}
                for gg, ll in tmp:
                    if gg not in m or ll > m[gg]:
                        m[gg] = ll
                runs = list(m.items())
                longest = 0
                for gg, ll in runs:
                    if gg >= 2 and ll > longest:
                        longest = ll
                if longest > L:
                    cnt += 1
                    runs = []
            return cnt
        lo, hi, ans = 0, n, n
        while lo <= hi:
            mid = (lo + hi) // 2
            if breakers_needed(mid) <= maxC:
                ans = mid
                hi = mid - 1
            else:
                lo = mid + 1
        return ans

