var minStable = function(nums, maxC) {
    const n = nums.length;
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const breakersNeeded = (L) => {
        if (L >= n) return 0;
        let cnt = 0;
        let runs = [];
        for (const x of nums) {
            const tmp = [[x, 1]];
            for (const [pg, pl] of runs) tmp.push([gcd(pg, x), pl + 1]);
            const m = new Map();
            for (const [gg, ll] of tmp) {
                if (!m.has(gg) || ll > m.get(gg)) m.set(gg, ll);
            }
            runs = Array.from(m.entries());
            let longest = 0;
            for (const [gg, ll] of runs) {
                if (gg >= 2 && ll > longest) longest = ll;
            }
            if (longest > L) { cnt++; runs = []; }
        }
        return cnt;
    };
    let lo = 0, hi = n, ans = n;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (breakersNeeded(mid) <= maxC) { ans = mid; hi = mid - 1; }
        else lo = mid + 1;
    }
    return ans;
};
